changeSet.sql:
ALTER TABLE settlements DROP CONSTRAINT IF EXISTS fk_settlements_trade;
ALTER TABLE settlements ADD COLUMN trade_date DATE;
UPDATE settlements AS s SET trade_date = t.trade_date FROM trades AS t WHERE s.trade_id = t.id AND s.trade_date IS NULL;
ALTER TABLE settlements ALTER COLUMN trade_date SET NOT NULL;
ALTER TABLE trades RENAME TO trades_legacy;
CREATE TABLE trades_partitioned ( id BIGINT GENERATED BY DEFAULT AS IDENTITY, trade_ref VARCHAR(30) NOT NULL, instrument_id BIGINT NOT NULL, counterparty_id BIGINT NOT NULL, asset_class VARCHAR(20) NOT NULL, side VARCHAR(4) NOT NULL, quantity NUMERIC(18,4) NOT NULL, price NUMERIC(18,4) NOT NULL, trade_date DATE NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'PENDING', deleted_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, modified_at TIMESTAMPTZ,
CONSTRAINT pk_trades PRIMARY KEY (id, trade_date), CONSTRAINT uq_trades_trade_ref_date UNIQUE (trade_ref, trade_date), CONSTRAINT fk_trades_instrument FOREIGN KEY (instrument_id) REFERENCES instruments(id), CONSTRAINT fk_trades_counterparty FOREIGN KEY (counterparty_id) REFERENCES counterparties(id) ) PARTITION BY RANGE (trade_date);
CREATE TABLE trades_y2026m04 PARTITION OF trades_partitioned FOR VALUES FROM ('2026-04-01') TO ('2026-05-01');
CREATE TABLE trades_y2026m05 PARTITION OF trades_partitioned FOR VALUES FROM ('2026-05-01') TO ('2026-06-01');
CREATE TABLE trades_y2026m06 PARTITION OF trades_partitioned FOR VALUES FROM ('2026-06-01') TO ('2026-07-01');
CREATE TABLE trades_y2026m07 PARTITION OF trades_partitioned FOR VALUES FROM ('2026-07-01') TO ('2026-08-01');
CREATE TABLE trades_default PARTITION OF trades_partitioned DEFAULT;
INSERT INTO trades_partitioned ( id, trade_ref, instrument_id, counterparty_id, asset_class, side, quantity, price, trade_date, status, deleted_at, created_at, modified_at ) SELECT id, trade_ref, instrument_id, counterparty_id, asset_class, side, quantity, price, trade_date, status, deleted_at, created_at, modified_at FROM trades_legacy;
SELECT setval( pg_get_serial_sequence('trades_partitioned', 'id'), COALESCE((SELECT MAX(id) FROM trades_partitioned), 1), EXISTS (SELECT 1 FROM trades_partitioned) );
DROP TABLE trades_legacy; ALTER TABLE trades_partitioned RENAME TO trades;
CREATE INDEX idx_trades_trade_date ON trades (trade_date);
CREATE INDEX idx_trades_status ON trades (status);
CREATE INDEX idx_trades_instrument_id ON trades (instrument_id);
CREATE INDEX idx_trades_counterparty_id ON trades (counterparty_id);
ALTER TABLE settlements ADD CONSTRAINT fk_settlements_trade FOREIGN KEY (trade_id, trade_date) REFERENCES trades (id, trade_date);

rollback.sql:
ALTER TABLE settlements DROP CONSTRAINT IF EXISTS fk_settlements_trade;
ALTER TABLE trades RENAME TO trades_partitioned_rollback;
CREATE TABLE trades_unpartitioned ( id BIGINT GENERATED BY DEFAULT AS IDENTITY, trade_ref VARCHAR(30) NOT NULL, instrument_id BIGINT NOT NULL, counterparty_id BIGINT NOT NULL, asset_class VARCHAR(20) NOT NULL, side VARCHAR(4) NOT NULL, quantity NUMERIC(18,4) NOT NULL, price NUMERIC(18,4) NOT NULL, trade_date DATE NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'PENDING', deleted_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, modified_at TIMESTAMPTZ,
CONSTRAINT pk_trades_unpartitioned PRIMARY KEY (id), CONSTRAINT uq_trades_unpartitioned_trade_ref UNIQUE (trade_ref), CONSTRAINT fk_trades_unpartitioned_instrument FOREIGN KEY (instrument_id) REFERENCES instruments(id), CONSTRAINT fk_trades_unpartitioned_counterparty FOREIGN KEY (counterparty_id) REFERENCES counterparties(id) );
INSERT INTO trades_unpartitioned ( id, trade_ref, instrument_id, counterparty_id, asset_class, side, quantity, price, trade_date, status, deleted_at, created_at, modified_at ) SELECT id, trade_ref, instrument_id, counterparty_id, asset_class, side, quantity, price, trade_date, status, deleted_at, created_at, modified_at FROM trades_partitioned_rollback;
SELECT setval( pg_get_serial_sequence('trades_unpartitioned', 'id'), COALESCE((SELECT MAX(id) FROM trades_unpartitioned), 1), EXISTS (SELECT 1 FROM trades_unpartitioned) );
DROP TABLE trades_partitioned_rollback CASCADE; ALTER TABLE trades_unpartitioned RENAME TO trades;
CREATE INDEX idx_trades_trade_date ON trades (trade_date);
CREATE INDEX idx_trades_status ON trades (status);
ALTER TABLE settlements DROP COLUMN trade_date;
ALTER TABLE settlements ADD CONSTRAINT fk_settlements_trade FOREIGN KEY (trade_id) REFERENCES trades (id);
